    t.variableDeclaration('const', [
      t.variableDeclarator(
        t.identifier(splitMeta.localExporterIdent),
        splitNode,
      ),
    ]),
  )
} else {
  console.info('Unexpected splitNode type:', splitNode)
  throw new Error(`Unexpected splitNode type ☝️: ${splitNode.type}`)
}

